; This file was edited using TECkitMappingEditorU.exe v4.0.0.0 on 12/18/2021.
;   Conversion Type = Unicode_to_from_Unicode
;   Left-hand side font = Microsoft Sans Serif;11.25
;   Right-hand side font = Microsoft Sans Serif;11.25
;   Main Window Position = 0,0,750,680
;   Left-hand side Character Map Window Position = 745,0,457,447
;   Right-hand side Character Map Window Position = 742,441,457,239
;   Left-hand range = 0000-007F
;   Right-hand range = 0280-02FF

; TECkit mapping file for PBS Urdu Romanization to Urdu Unicode,
; with SIL DoulosNPC (phonetic) as an intermediary.
; No attempt is made to handle unwritten vowels.

; Version 0.1 -- bb --   7 February 2004  Very rough draft.
; Version 0.2 -- bb -- 18 December 2021 Map to ICU Latin, add short vowel
;												(later changed to stay with Indological)
; Version 0.2 -- bb --  5 February 2022  Add fathatan
; Version 0.4 -- bb -- 17 May 2022  Adjust for dev test
; Version 0.5 -- bb -- 07 Sep 2022  Change name to indol2urdu-bb.map, and 
;											use short i for hamza instead of long i (needs research)
;											fixed more hamza cases, and aspiration.
; Version 0.6 -- bb -- 07 Sep 2022  Add non-Urdu characters
; Version 0.7 -- bb -- 16 Dec 2022  Fix some shadda behavior, other tweaks
; Version 0.8 -- bb -- 18 Dec 2022  Harmonize with map for other languages
; Version 0.9 -- bb -- 18 Dec 2022  Add rules for quote marks
; Version 1.0 -- bb -- 13 Jan 2023	Adjust for Paratext UI: map roman to roman, fix apostrophe, no digit mapping
; Version 1.1 -- bb -- 03 Jun 2025	Adjust to incorporate the PBS Roman->NPC map as a layer 
; Version 1.2 -- bb -- 20 Jun 2025	Try inserting short vowel again

LHSName	"PBS-Latin"
LHSDescription	"PBS Latin Urdu"
RHSName	"Urdu-ABS"
RHSDescription	"Urdu ABS Unicode"


;; Separate pass for Capitalization
pass(Unicode)

Class [Lower] = ( latin_small_letter_a .. latin_small_letter_z latin_small_letter_a_with_acute latin_small_letter_i_with_acute latin_small_letter_u_with_acute )
Class [Upper] = ( latin_capital_letter_a .. latin_capital_letter_z latin_capital_letter_a_with_acute latin_capital_letter_i_with_acute latin_capital_letter_u_with_acute )

[Upper]		<>	[Lower] / greek_capital_letter_psi _ 

;; Remove the flag for capitalization
[Upper]=Ltr		< 	greek_capital_letter_psi [Lower]=Ltr
 


