;; Map for PBS characters to Indological (NPC)

;; For aspiration rules
;; Voiced Phonetic obstruents
;; (Including l for dulha)
Class [VdPhObs] = ( \
latin_small_letter_b \
latin_small_letter_d \
latin_small_letter_d_with_dot_below \
latin_small_letter_l \
latin_small_letter_r \
latin_small_letter_r_with_dot_below \
latin_small_letter_j \
latin_small_letter_g \
)

;; Voiceless Phonetic obstruents
Class [VlPhObs] = ( \
latin_small_letter_p \
latin_small_letter_t \
latin_small_letter_t_with_dot_below \
latin_small_letter_c_with_caron \
latin_small_letter_k \
)

Class [Obs] = ( \
[VdPhObs] [VlPhObs] \
)

;; Aspiration
latin_small_letter_h / [Obs] _		<>	modifier_letter_small_h


;; Affricates/fricatives
latin_small_letter_j									<>	latin_small_letter_j_with_caron
latin_small_letter_c latin_small_letter_h	<>	latin_small_letter_c_with_caron
latin_small_letter_z latin_small_letter_h	<>	latin_small_letter_z_with_caron
latin_small_letter_s latin_small_letter_h	<>	latin_small_letter_s_with_caron
latin_small_letter_k combining_dot_below latin_small_letter_h	<>	latin_small_letter_x
;; They are not writing ghain different from gaf, so we only can map in one direction
;latin_small_letter_g combining_dot_below	<>	latin_small_letter_gamma
latin_small_letter_g										< 	latin_small_letter_gamma

;; Other letters
;; Not needed
; latin_small_letter_g	<>		latin_small_letter_g_with_bowl

;; Check on words like "color" rang
;latin_small_letter_n_with_line_below latin_small_letter_g		<>	tilde	latin_small_letter_g
latin_small_letter_n_with_line_below		<>	tilde

;; Now this map uses w instead of v, so we don't need this mapping
;latin_small_letter_w			<>		latin_small_letter_v		;; different between PBS and ICU

;; Vowels
; They want a-circumflex for zabar.  We'll map it here.  No, holding back
;latin_small_letter_a_with_circumflex	<>	latin_small_letter_a
latin_small_letter_a combining_circumflex_accent	> latin_small_letter_a
; For all the long vowels, they want acute
latin_small_letter_a_with_acute		<>	latin_small_letter_a_with_macron
latin_small_letter_i_with_acute			<>	latin_small_letter_i_with_macron
latin_small_letter_u_with_acute		<>	latin_small_letter_u_with_macron

;; Diphthongs
;; Can't tell the difference between long e and short e at the end of a word
latin_small_letter_a latin_small_letter_i / _ ^[PhLtr] 		<>	latin_small_letter_open_e
latin_small_letter_a latin_small_letter_i 						 >	latin_small_letter_e
;latin_small_letter_e			 < 	latin_small_letter_open_e
latin_small_letter_a latin_small_letter_u		<>	latin_small_letter_open_o


;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
; Fixes for NPC and ICU.
; In some versions of NPC (when?), the caron is separate from the c.
; But the ABS map is easier to write if they're a single character.
; Leave it combined for the ICU Latin version.
latin_small_letter_c combining_caron	 >	latin_small_letter_c_with_caron

; Fix potential problems in the encoding
latin_small_letter_script_g		 >	latin_small_letter_g
combining_overline					 >	combining_macron
latin_small_letter_dotless_i		 >	latin_small_letter_i
latin_small_letter_a combining_macron	 >	latin_small_letter_a_with_macron
;latin_small_letter_a_with_macron 	<>	latin_small_letter_a combining_macron
;latin_small_letter_i_with_macron 		<>	latin_small_letter_i combining__macron
;latin_small_letter_u_with_macron 	<>	latin_small_letter_u combining_macron
;latin_small_letter_t_with_dot_below 	<>	latin_small_letter_t combining_dot_below

; For some sources, put RLM around the left and right "floor" marks
left_floor      <>      left_to_right_mark left_floor
right_floor      <>      left_to_right_mark right_floor
; Probably don't need zero-width joiner, for going to latin or Urdu script
; (TODO: but we would like to add it back in, going the other direction)
zero_width_joiner    >  

; For now, delete any possible tone marks
combining_grave_accent 	 >	
combining_acute_accent	 >	


;; Separate pass for Geminates

;; GEMINATES

latin_small_letter_p latin_small_letter_p		<>	latin_small_letter_p modifier_letter_triangular_colon
latin_small_letter_t latin_small_letter_t		<>	latin_small_letter_t modifier_letter_triangular_colon
latin_small_letter_t_with_dot_below latin_small_letter_t_with_dot_below <>	latin_small_letter_t_with_dot_below modifier_letter_triangular_colon
