latin_small_letter_d latin_small_letter_d		<>	latin_small_letter_d modifier_letter_triangular_colon
latin_small_letter_d_with_dot_below latin_small_letter_d_with_dot_below <>	latin_small_letter_d_with_dot_below modifier_letter_triangular_colon
latin_small_letter_j_with_caron latin_small_letter_j_with_caron	<>	latin_small_letter_j_with_caron modifier_letter_triangular_colon
latin_small_letter_g latin_small_letter_g		<>	latin_small_letter_g modifier_letter_triangular_colon
latin_small_letter_f latin_small_letter_f		<>	latin_small_letter_f modifier_letter_triangular_colon
latin_small_letter_gamma latin_small_letter_gamma	<>	latin_small_letter_gamma modifier_letter_triangular_colon
latin_small_letter_x latin_small_letter_x		<>	latin_small_letter_x modifier_letter_triangular_colon
latin_small_letter_l latin_small_letter_l		<>	latin_small_letter_l modifier_letter_triangular_colon
latin_small_letter_l_with_dot_below latin_small_letter_l_with_dot_below <>	latin_small_letter_l_with_dot_below modifier_letter_triangular_colon
latin_small_letter_m latin_small_letter_m		<>	latin_small_letter_m modifier_letter_triangular_colon
latin_small_letter_n latin_small_letter_n		<>	latin_small_letter_n modifier_letter_triangular_colon
latin_small_letter_n_with_dot_below latin_small_letter_n_with_dot_below <>	latin_small_letter_n_with_dot_below modifier_letter_triangular_colon
latin_small_letter_q latin_small_letter_q	<>	latin_small_letter_q modifier_letter_triangular_colon
latin_small_letter_r latin_small_letter_r		<>	latin_small_letter_r modifier_letter_triangular_colon
latin_small_letter_r_with_dot_below latin_small_letter_r_with_dot_below <>	latin_small_letter_r_with_dot_below modifier_letter_triangular_colon
latin_small_letter_s latin_small_letter_s		<>	latin_small_letter_s modifier_letter_triangular_colon
latin_small_letter_s_with_caron latin_small_letter_s_with_caron	<>	latin_small_letter_s_with_caron modifier_letter_triangular_colon
