Class [PhCons] = (\
[PhConsNoMod] \
modifier_letter_small_h \
modifier_letter_triangular_colon \
)

; Turn this off?  I was getting aspiration where I should have gotten an h.

; Attempt to put a short a between all consonant clusters, 
; and after final consonants? omit this part for now۔
; Try to put it between the first and second, but not second and third.
; Not sure what will happen with longer words.
; Insert on Latin side; [could delete on ABS side, but let's not for now]
; Don't insert between a consonant and a length marker or aspiration (NoMod).  After is okay.
; Try omitting heh gol also?  No, that didn't work.
; I'd like to see if I could treat "dh" and "ht" as a single consonant somehow.
;([PhCons])=cons1 latin_small_letter_a ([PhCons])=cons2 ([PhCons])=cons3 latin_small_letter_a ([PhCons])=cons4         <   ( @cons1 ) ( @cons2 ) ( @cons3 ) ( @cons4 ) / _ [PhConsNoMod]
;([PhCons])=cons1 latin_small_letter_a ([PhCons])=cons2 ([PhCons])=cons3 latin_small_letter_a         <   ( @cons1 ) ( @cons2 ) ( @cons3 ) / _ [PhConsNoMod]
([PhCons])=cons1 latin_small_letter_a ([PhCons])=cons2 ([PhCons])=cons3 latin_small_letter_a ([PhCons])=cons4         <   ( @cons1 ) ( @cons2 ) ( @cons3 ) ( @cons4 )
([PhCons])=cons1 latin_small_letter_a ([PhCons])=cons2 ([PhCons])=cons3         <   ( @cons1 ) ( @cons2 ) ( @cons3 )
([PhCons])=cons latin_small_letter_a         <   ( @cons ) / _ [PhConsNoMod]




