;; Main map

; aspiration  [CHECK the ABS->NPC direction for these rules]
; map regular h only in the ->ABS direction
; use superscript h for latin direction
;latin_small_letter_h combining_ring_below	 >	arabic_letter_heh_doachashmee
latin_small_letter_h / [PhObs] modifier_letter_triangular_colon _	 >	arabic_letter_heh_doachashmee
latin_small_letter_h / [PhObs] _	 >	arabic_letter_heh_doachashmee
modifier_letter_small_h / [PhObs] modifier_letter_triangular_colon  _	<>	arabic_letter_heh_doachashmee
modifier_letter_small_h / [PhObs]  _	<>	arabic_letter_heh_doachashmee
; Mapping heh goal in the other direction below, so it comes after more specific rules
latin_small_letter_h			 > 	arabic_letter_heh_goal


; Continuants
latin_small_letter_f			<>	arabic_letter_feh				
