latin_small_letter_n			<>	arabic_letter_noon				
; Before a g, noon is often a nasal rather than an 'n'
latin_small_letter_n_with_dot_below / _ latin_small_letter_g	<>	arabic_letter_rnoon / _ arabic_letter_gaf				
latin_small_letter_n_with_dot_below	<>	arabic_letter_rnoon				
