;; GEMINATES
modifier_letter_triangular_colon	<>	arabic_shadda
; kasra and damma apparently get reordered before the shadda.
; To get the colon on the right side of the vowel when going to indological,
; need special rules.
modifier_letter_triangular_colon latin_small_letter_i	<	arabic_kasra arabic_shadda
