; When there is a shadda after aspiration, it applies to the consonant before the aspiration
modifier_letter_triangular_colon modifier_letter_small_h <>     arabic_letter_heh_doachashmee arabic_shadda
; When there is a shadda after vau, the vau is a consonant
latin_small_letter_w modifier_letter_triangular_colon <>     arabic_letter_waw arabic_shadda

